        function cargarComboFac(url) {
            sid = $("#is_delete").val();
            var url = base_url+"/pos/itmsuspend/"+sid;
            $.get(url, function(data) {
                if (data) {
                    $("#artDiv").html("");
                    $.each(JSON.parse(data), function(index, value) {
                        $("#artDiv").append("<tr style='cursor:pointer; ' quantity ='" + value.quantity + "' product_name = '" + value.product_name + "' cantoriginal='" + value.quantity + "' id='" + value.product_id + "' class='itmsuspdiv'><td class='text-left'>" + value.product_name +
                            "</td><td id='thQty_" + value.product_id + "' class='text-center'>" + value.quantity + "</td></tr>");

                    });
                    $(".itmsuspdiv").on('click', function() {
                        id_div = $("#ctaselected").val();
                        selected_table = $('#tbCuentas_' + id_div);
                        cantoriginal = parseInt($(this).attr('cantoriginal'));
                        product_id = $(this).attr('id');
                        quantity = parseInt($(this).attr('quantity'));
                        product_name = $(this).attr('product_name');
                        dismis = quantity - 1;
                        // aux = $("incrementQty_"+product_id);
                        if (id_div !== '') {
                            if (dismis >= 0) {
                                is_exist = selected_table.parents("table").find("tr").find("#incrementQty_" + product_id);
                                if (typeof is_exist.html() !== "undefined") {
                                    // console.log(is_exist.html());
                                    qty = parseInt(is_exist.html()) + 1;
                                    is_exist.html(qty);
                                    $('#CtaQtyInput_'+product_id).attr('value', qty);
                                    $('#CtaQtyInput_'+product_id).val(qty);

                                    $("#thQty_" + product_id).html(dismis);
                                    $(this).attr('quantity', quantity - 1);
                                } else {
                                    $(this).attr('quantity', quantity - 1);
                                    tr =
                                        '<tr style="cursor:pointer;" cantoriginal="' + cantoriginal + '" id="' + product_id + '" class="itmcuentadiv">' +
                                        '<td>' + product_name + '</td><td id=incrementQty_' + product_id + ' >' + 1 + '</td>' + 
                                        '<td><i class="fa fa-times-circle deleteitmcta" onclick="deleteitmcta(this);" aria-hidden="true"></i>'+
                                        '<input type="hidden" name="CtaQty['+id_div+'][]" value="1" id="CtaQtyInput_' + product_id + '" />'+
                                        '<input type="hidden" name="idproduct['+id_div+'][]" value="'+product_id+'" /></td>' + 
                                        '</td></tr>';
                                    $(selected_table).append(tr);
                                    $("#thQty_" + product_id).html(dismis);
                                }
                            } else {
                                bootbox.alert("No hay disponibles");
                            }
                        } else {
                            bootbox.alert("Seleccione una cuenta");
                        }
                    });
                
                } else {
                    console.log("no hay items");
                }
            });
        }

        function deleteitmcta(element) {
            var product_id = $(element).parent().parent().attr("id");
            var id_div = $(element).parent().parent().parent().parent().parent().attr("id");
            selected_table = $('#tbCuentas_' + id_div);
            is_exist = selected_table.parents("table").find("tr").find("#incrementQty_" + product_id);
            table = $("#thQty_" + product_id).parents('tr');
            count = 1;
            if (typeof is_exist.html() !== "undefined") {
                qty = parseInt(is_exist.html());
                quantity = parseInt(table.attr('quantity'));
                res = qty-1;
                cantoriginal = parseInt(table.attr('cantoriginal'));
                product_id = table.attr('id');
                total = quantity + 1;

                $('#CtaQtyInput_'+product_id).attr('value', res);
                $('#CtaQtyInput_'+product_id).val(res);
                $("#thQty_" + product_id).html(total);
                table.attr('quantity', total);
                if(res==0)
                {
                    value = selected_table.parents("table").find("#" + product_id).remove();
                }else{
                    // console.log('res ', res);
                    is_exist.html(res);
                   
                }
            }

        }

        $(function() {
            $("#qty_cuentas").on("change", function() {
                cargarComboFac();
                $("#divCuentas").html("");
                var cantdiv = parseInt($(this).val());
                for (i = 1; i <= cantdiv; i++) {
                    $("#divCuentas").append(
                        '<div id="' + i + '" class="cuenta tableFixHead col-lg-12 col-md-12 col-sm-12" style="min-height: 155px;max-height: 155px; border:solid 1px #9c9c9c;">' +
                        '<label>Cuenta #' + i + '</label><input type="text" placeholder="Referencia" class="form-control" style="max-height: 20px;" name="hold_ref_'+i+'"><table class="table table-striped">' +
                        '<thead><tr scope="col"><td>Articulo</td><td>Cantidad</td><td>Acci&oacute;n</td></tr></thead>' +
                        '<tbody style="height: 155px !important; overflow: scroll;" id="tbCuentas_' + i + '"></tbody></table></div>'
                    );
                }
                $(".cuenta").on("click", function() {
                    // console.log($(this));
                    $(".cuenta").css("background-color", "white");
                    $(this).css("background-color", "#00a65a;");
                    $("#ctaselected").val($(this).attr('id'));
                    $("#ctaselected").attr('value', $(this).attr('id'));
                });
            });
        });

        $("#add_receivable").click(function()
        {
            var total = $("#tblReceivable tbody tr").length;
            var count = 0;
            $("#tblReceivable tbody tr").each(function (index) {

                var campo1, campo2, campo3;
                $(this).children("td").each(function (index2) {
                    switch (index2) {
                        case 0:
                            campo1 = $(this).text();
                        break;
                        case 1:
                            campo2 = $(this).text();
                        break;
                    }
                    if(typeof campo2 !== "undefined")
                    {
                       if(campo2 == 0){
                            count++;
                       }
                    }
                });
            });
            if(count === total)
            {
                $("#pos-receivable-form").submit();
            }else
            {
                bootbox.alert("Faltan productos de agregar a las cuentas");
            }
        });